  // PART: UTILS
  const NS='http://www.w3.org/2000/svg';
  const DEFAULT_BOX_COLORS=['#0072B2','#D55E00','#009E73','#CC79A7','#E69F00','#56B4E9','#F0E442','#000000'];
  const DEFAULT_BOX_GRAYSCALE_COLORS=['#000000','#4d4d4d','#7a7a7a','#a6a6a6','#c9c9c9','#e0e0e0'];
  const DEFAULT_GRAYSCALE_UNIFIED_FILL = '#7a7a7a';
  const DEFAULT_UNIFIED_SYMBOL_FILL = '#000000';
  const DEFAULT_UNIFIED_SYMBOL_BORDER = 'none';
  const DEFAULT_ROWS=100, DEFAULT_COLS=10;
  const DEFAULT_AXIS_COLOR='#000000';
  const DEFAULT_GRID_COLOR='#dddddd';
  const MIN_MINOR_TICK_SUBDIVISIONS = 1;
  const MAX_MINOR_TICK_SUBDIVISIONS = 9;
  const DEFAULT_X_DATASET_SPACING = 1;
  const MIN_X_DATASET_SPACING = 0.2;
  const MAX_X_DATASET_SPACING = 1;
  const X_DATASET_SPACING_STEP = 0.05;
  const STRIP_INTER_DATASET_GAP_FACTOR = 0.70;
  const STRIP_INTER_DATASET_MIN_GAP_PX = 4;
  const STRIP_MIN_RADIUS_ASYMPTOTE = 0.2;
  const STRIP_RADIUS_REFERENCE_COUNT = 11;
  const STRIP_RADIUS_MEDIUM_COUNT = 140;
  const STRIP_RADIUS_COUNT_OFFSET = 20;
  const STRIP_RADIUS_MEDIUM_RELATIVE_SCALE = 0.375;
  const STRIP_MEDIUM_SPREAD_MIN_SCALE = 0.5;
  const STRIP_MEDIUM_SPREAD_LOG_CENTER = Math.log10(140 + 1);
  const STRIP_MEDIUM_SPREAD_LOG_SIGMA = 0.32;
  const DEFAULT_MINOR_TICK_SUBDIVISIONS = Number.isFinite(chartStyle.DEFAULT_MINOR_TICK_SUBDIVISIONS)
    ? chartStyle.DEFAULT_MINOR_TICK_SUBDIVISIONS
    : 3;

  function seedBoxDefaultHeaderRow(matrix){
    if(!Array.isArray(matrix) || !Array.isArray(matrix[0])){
      return matrix;
    }
    const headerRow = matrix[0];
    const groupCount = Math.min(headerRow.length, 3);
    for(let idx = 0; idx < groupCount; idx += 1){
      headerRow[idx] = `Group ${idx + 1}`;
    }
    return matrix;
  }

  function ensureBoxDefaultHeaderRow(hotInstance){
    const hot = hotInstance || state.hot;
    if(!hot || typeof hot.getData !== 'function' || typeof hot.setDataAtCell !== 'function'){
      return false;
    }
    const data = hot.getData() || [];
    const headerRow = Array.isArray(data[0]) ? data[0] : [];
    const hasBodyData = data.slice(1).some(row => Array.isArray(row) && row.some(value => value != null && String(value).trim() !== ''));
    if(hasBodyData){
      return false;
    }
    const desiredCols = Math.min(Math.max(typeof hot.countCols === 'function' ? hot.countCols() : headerRow.length, 0), 3);
    if(desiredCols <= 0){
      return false;
    }
    const changes = [];
    for(let col = 0; col < desiredCols; col += 1){
      const current = headerRow[col] != null ? String(headerRow[col]).trim() : '';
      const desired = `Group ${col + 1}`;
      if(!current){
        changes.push([0, col, desired]);
      }
    }
    if(!changes.length){
      return false;
    }
    hot.setDataAtCell(changes, 'box-default-header-seed');
    return true;
  }

  function clampMinorTickSubdivisions(value){
    const numeric = Number(value);
    if(!Number.isFinite(numeric)){
      return DEFAULT_MINOR_TICK_SUBDIVISIONS;
    }
    const rounded = Math.round(numeric);
    return Math.max(MIN_MINOR_TICK_SUBDIVISIONS, Math.min(MAX_MINOR_TICK_SUBDIVISIONS, rounded));
  }

  function sanitizeXAxisDatasetSpacing(value){
    const numeric = Number(value);
    if(!Number.isFinite(numeric) || numeric <= 0){
      return DEFAULT_X_DATASET_SPACING;
    }
    return Math.max(MIN_X_DATASET_SPACING, Math.min(MAX_X_DATASET_SPACING, numeric));
  }
  function resolveResponsivePointRadius(baseRadius, scaleInfo, options = {}){
    const base = Number(baseRadius);
    const minRadius = Number.isFinite(Number(options?.min)) ? Number(options.min) : 0;
    const context = typeof options?.context === 'string' && options.context.trim()
      ? options.context.trim()
      : 'box-point';
    const scaleRadiusFn = chartStyle && typeof chartStyle.scaleRadius === 'function'
      ? chartStyle.scaleRadius
      : null;
    const legacyRadius = scaleRadiusFn
      ? scaleRadiusFn(base, scaleInfo, { context, min: minRadius })
      : Math.max(minRadius, Number.isFinite(base) && base > 0 ? base : minRadius);
    if(!Number.isFinite(base) || base <= 0){
      return legacyRadius;
    }
    const scaleWRaw = Number(scaleInfo?.scaleW);
    const scaleHRaw = Number(scaleInfo?.scaleH);
    if(!Number.isFinite(scaleWRaw) || scaleWRaw <= 0 || !Number.isFinite(scaleHRaw) || scaleHRaw <= 0){
      return legacyRadius;
    }
    const minScaleBound = Number.isFinite(Number(chartStyle?.RESIZE_MIN_SCALE)) ? Number(chartStyle.RESIZE_MIN_SCALE) : 0.3;
    const maxScaleBound = Number.isFinite(Number(chartStyle?.RESIZE_MAX_SCALE)) ? Number(chartStyle.RESIZE_MAX_SCALE) : 3;
    const clampScale = value => {
      const numeric = Number(value);
      if(!Number.isFinite(numeric)){
        return 1;
      }
      return Math.max(minScaleBound, Math.min(maxScaleBound, numeric));
    };
    const scaleW = clampScale(scaleWRaw);
    const scaleH = clampScale(scaleHRaw);
    const areaScale = Math.max(1e-9, scaleW * scaleH);
    const legacyResizeScale = Math.pow(areaScale, 0.25);
    const geometricScale = Math.sqrt(areaScale);
    const minAxisScale = Math.min(scaleW, scaleH);
    const maxAxisScale = Math.max(scaleW, scaleH);
    const anisotropyRatio = maxAxisScale > 0
      ? Math.max(0.05, Math.min(1, minAxisScale / maxAxisScale))
      : 1;
    const anisotropyCompensation = Math.pow(anisotropyRatio, 0.3);
    let targetResizeScaleRaw = geometricScale * anisotropyCompensation;
    if(scaleW < 1 && scaleH < 1){
      const combinedShrinkExponent = 0.35 * anisotropyRatio;
      targetResizeScaleRaw *= Math.pow(Math.max(1e-9, geometricScale), combinedShrinkExponent);
    }
    const targetResizeScale = clampScale(targetResizeScaleRaw);
    const correction = targetResizeScale / Math.max(1e-6, legacyResizeScale);
    const correctedRadius = legacyRadius * correction;
    const maxRadius = Math.max(minRadius, base * maxScaleBound);
    if(!Number.isFinite(correctedRadius) || correctedRadius <= 0){
      return legacyRadius;
    }
    return Math.max(minRadius, Math.min(maxRadius, correctedRadius));
  }
  const DEFAULT_VIOLIN_BANDWIDTH=1;
  const DEFAULT_VIOLIN_SAMPLE_COUNT=80;

  function normalizeBoxTableFormat(value){
    return value === 'grouped' ? 'grouped' : 'single';
  }

  function getBoxDefaultColorSchemeId(tableFormat){
    return normalizeBoxTableFormat(tableFormat) === 'grouped' ? 'scientific' : 'grayscale';
  }

  function getBoxDefaultPalette(tableFormat){
    return normalizeBoxTableFormat(tableFormat) === 'grouped'
      ? DEFAULT_BOX_COLORS
      : DEFAULT_BOX_GRAYSCALE_COLORS;
  }

  function getBoxDefaultFillColor(tableFormat){
    const palette = getBoxDefaultPalette(tableFormat);
    return palette[0] || '#000000';
  }


  const BOX_CLEANUP_DEBUG = false;

  function boxCleanupDebug(message, payload){
    if(!BOX_CLEANUP_DEBUG){
      return;
    }
    if(arguments.length > 1){
      console.debug(message, payload);
      return;
    }
    console.debug(message);
  }

  function applyStrokePatternToNodes(nodes, width, patternValue){
    const attrs = getSummaryStrokePatternAttrs(width, patternValue);
    (Array.isArray(nodes) ? nodes : []).forEach(node => {
      if(!node){
        return;
      }
      if(attrs['stroke-dasharray']){
        node.setAttribute('stroke-dasharray', attrs['stroke-dasharray']);
      }else{
        node.removeAttribute('stroke-dasharray');
      }
      if(attrs['stroke-linecap']){
        node.setAttribute('stroke-linecap', attrs['stroke-linecap']);
      }
    });
  }

  function createBoxCanvasForeignObjectSurface(doc, bounds, rendererType){
    if(!doc || !bounds){
      return null;
    }
    const minX = Number(bounds.minX);
    const minY = Number(bounds.minY);
    const width = Math.max(1, Math.ceil(Number(bounds.width) || 0));
    const height = Math.max(1, Math.ceil(Number(bounds.height) || 0));
    if(!Number.isFinite(minX) || !Number.isFinite(minY) || width <= 0 || height <= 0){
      boxCleanupDebug('Debug: box canvas surface skipped due to invalid bounds', { bounds, rendererType });
      return null;
    }
    const foreignObject = doc.createElementNS(NS, 'foreignObject');
    foreignObject.setAttribute('x', String(minX));
    foreignObject.setAttribute('y', String(minY));
    foreignObject.setAttribute('width', String(width));
    foreignObject.setAttribute('height', String(height));
    foreignObject.setAttribute('data-point-renderer', rendererType);
    const canvas = doc.createElement('canvas');
    canvas.setAttribute('xmlns', 'http://www.w3.org/1999/xhtml');
    canvas.style.display = 'block';
    canvas.style.width = `${width}px`;
    canvas.style.height = `${height}px`;
    canvas.style.background = 'transparent';
    canvas.style.pointerEvents = 'none';
    const dpr = Math.max(1, (global.window?.devicePixelRatio || 1) * BOX_POINT_CANVAS_RESOLUTION_SCALE);
    canvas.setAttribute('data-resolution-scale', String(BOX_POINT_CANVAS_RESOLUTION_SCALE));
    canvas.width = Math.max(1, Math.ceil(width * dpr));
    canvas.height = Math.max(1, Math.ceil(height * dpr));
    const ctx = canvas.getContext('2d');
    if(!ctx){
      boxCleanupDebug('Debug: box canvas surface skipped because 2D context is unavailable', { rendererType, width, height });
      return null;
    }
    return { foreignObject, canvas, ctx, dpr, width, height, minX, minY };
  }

  function computeGaussianDensityProfile(sorted, bandwidth, domain, count, options = {}){
    const usePreallocatedArrays = options.usePreallocatedArrays === true;
    const positions = usePreallocatedArrays ? new Array(count) : [];
    const densities = usePreallocatedArrays ? new Array(count) : [];
    const step = (domain.domainMax - domain.domainMin) / Math.max(count - 1, 1);
    const denom = sorted.length * bandwidth * Math.sqrt(2 * Math.PI);
    let peak = 0;
    for(let idx = 0; idx < count; idx++){
      const x = domain.domainMin + step * idx;
      let sum = 0;
      for(let j = 0; j < sorted.length; j++){
        const u = (x - sorted[j]) / bandwidth;
        sum += Math.exp(-0.5 * u * u);
      }
      const density = denom ? sum / denom : 0;
      if(usePreallocatedArrays){
        positions[idx] = x;
        densities[idx] = density;
      }else{
        positions.push(x);
        densities.push(density);
      }
      if(density > peak){
        peak = density;
      }
    }
    return {
      positions,
      densities,
      peak,
      domainMin: domain.domainMin,
      domainMax: domain.domainMax
    };
  }

  async function finalizeFeasibleRadiusSearch(config){
    const probeRadius = typeof config?.probeRadius === 'function' ? config.probeRadius : null;
    const resolveHalfWidthCap = typeof config?.resolveHalfWidthCap === 'function'
      ? config.resolveHalfWidthCap
      : probe => probe?.availableHalfWidth;
    const baseRadius = Number(config?.baseRadius);
    const minRadius = Number(config?.minRadius);
    const radiusStep = Number(config?.radiusStep);
    const sampleSize = Number(config?.sampleSize) || 0;
    if(!probeRadius || !Number.isFinite(baseRadius) || baseRadius <= 0 || !Number.isFinite(minRadius) || minRadius <= 0){
      boxCleanupDebug('Debug: feasible radius search skipped due to invalid configuration', { baseRadius, minRadius, sampleSize });
      return null;
    }
    let baseProbe = await probeRadius(baseRadius);
    if(baseProbe?.cancelled){
      return null;
    }
    if(baseProbe?.fit){
      const roundedRadius = roundStripPointControlValue(baseProbe.radius, radiusStep, 'down');
      return {
        radius: Number.isFinite(roundedRadius) && roundedRadius > 0 ? roundedRadius : baseProbe.radius,
        halfWidthCap: resolveHalfWidthCap(baseProbe),
        sampleSize,
        fitted: true
      };
    }
    let low = minRadius;
    let lowProbe = await probeRadius(low);
    if(lowProbe?.cancelled){
      return null;
    }
    if(!lowProbe?.fit){
      const fallbackRadius = roundStripPointControlValue(low, radiusStep, 'down');
      return {
        radius: Number.isFinite(fallbackRadius) && fallbackRadius > 0 ? fallbackRadius : low,
        halfWidthCap: resolveHalfWidthCap(lowProbe),
        sampleSize,
        fitted: false
      };
    }
    let high = baseRadius;
    for(let iter = 0; iter < 12; iter++){
      if((high - low) <= 0.05){
        break;
      }
      const mid = (low + high) / 2;
      const midProbe = await probeRadius(mid);
      if(midProbe?.cancelled){
        return null;
      }
      if(midProbe?.fit){
        low = mid;
        lowProbe = midProbe;
      }else{
        high = mid;
      }
    }
    const roundedRadius = roundStripPointControlValue(low, radiusStep, 'down');
    return {
      radius: Number.isFinite(roundedRadius) && roundedRadius > 0 ? roundedRadius : low,
      halfWidthCap: resolveHalfWidthCap(lowProbe),
      sampleSize,
      fitted: true
    };
  }

  function buildPostHocPairResult(pr, config = {}){
    const indices = Array.isArray(config.indices) ? config.indices : [];
    const traces = Array.isArray(config.traces) ? config.traces : [];
    const labels = Array.isArray(config.labels) ? config.labels : [];
    const groups = Array.isArray(config.groups) ? config.groups : [];
    const ai = indices[pr.i];
    const bi = indices[pr.j];
    const effectMetrics = computeEffectSizeMetrics(traces[ai].rawY, traces[bi].rawY, { paired: config.paired === true });
    const paramEffectMeta = config.paramEffectMeta;
    const nonParamEffectMeta = config.nonParamEffectMeta;
    const formattedParamEffect = formatEffectValue(effectMetrics.parametric?.[paramEffectMeta?.value], paramEffectMeta);
    const formattedNonParamEffect = formatEffectValue(effectMetrics.nonParametric?.[nonParamEffectMeta?.value], nonParamEffectMeta);
    const rangeMax = typeof config.getRenderedRangeMax === 'function' ? config.getRenderedRangeMax(ai, bi) : null;
    const pairResult = {
      a: pr.i,
      b: pr.j,
      ai,
      bi,
      p: config.pValueResolver ? config.pValueResolver(pr) : pr.p,
      adjP: config.adjustedPValueResolver ? config.adjustedPValueResolver(pr) : pr.pAdj,
      stat: config.statValueResolver ? config.statValueResolver(pr) : pr.stat,
      statName: config.statName || 'stat',
      df: config.dfResolver ? config.dfResolver(pr) : pr.df,
      diff: pr.diff,
      ciLow: pr.ciLow,
      ciHigh: pr.ciHigh,
      labelA: labels[pr.i],
      labelB: labels[pr.j],
      effects: effectMetrics,
      effectParametric: formattedParamEffect,
      effectNonParametric: formattedNonParamEffect,
      rangeMax,
      method: config.method || 'custom'
    };
    if(config.lognormalVariant){
      return { ...pairResult, ...convertToLognormalRatioResult(pr, groups[pr.i], groups[pr.j]) };
    }
    return pairResult;
  }

  function mapPostHocPairResults(pairList, config = {}){
    const sourcePairs = Array.isArray(pairList) ? pairList : [];
    const refIndex = Number.isInteger(config.refIndex) ? config.refIndex : null;
    const buildConfig = { ...config };
    delete buildConfig.refIndex;
    const resolvedPairs = refIndex == null
      ? sourcePairs
      : sourcePairs.filter(pr => pr.i === refIndex || pr.j === refIndex);
    return resolvedPairs.map(pr => buildPostHocPairResult(pr, buildConfig));
  }

  function buildStandardPairResult(config = {}){
    const pairResult = config.testResult || {};
    const rawAValues = Array.isArray(config.rawAValues) ? config.rawAValues : [];
    const rawBValues = Array.isArray(config.rawBValues) ? config.rawBValues : [];
    const effectMetrics = computeEffectSizeMetrics(rawAValues, rawBValues, { paired: config.paired === true });
    const paramEffectMeta = config.paramEffectMeta;
    const nonParamEffectMeta = config.nonParamEffectMeta;
    const formattedParamEffect = formatEffectValue(effectMetrics.parametric?.[paramEffectMeta?.value], paramEffectMeta);
    const formattedNonParamEffect = formatEffectValue(effectMetrics.nonParametric?.[nonParamEffectMeta?.value], nonParamEffectMeta);
    const statName = config.statName || (pairResult.t !== undefined ? 't' : pairResult.U !== undefined ? 'U' : pairResult.W !== undefined ? 'W' : 'stat');
    const statVal = config.statValue != null ? config.statValue : pairResult[statName];
    const rangeMax = typeof config.getRenderedRangeMax === 'function' ? config.getRenderedRangeMax(config.ai, config.bi) : null;
    const comparisonLabel = typeof config.comparisonLabel === 'string' && config.comparisonLabel.trim()
      ? config.comparisonLabel.trim()
      : `${config.labelA || 'A'} vs ${config.labelB || 'B'}`;
    const debugLabel = typeof config.debugLabel === 'string' && config.debugLabel.trim()
      ? config.debugLabel.trim()
      : 'Debug: box pair effect metrics';
    console.debug(debugLabel, {
      comparison: comparisonLabel,
      parametric: Object.fromEntries(Object.entries(effectMetrics.parametric).map(([key, val]) => [key, safeRound(val, 4)])),
      nonParametric: Object.fromEntries(Object.entries(effectMetrics.nonParametric).map(([key, val]) => [key, safeRound(val, 4)]))
    });
    return {
      a: config.a,
      b: config.b,
      ai: config.ai,
      bi: config.bi,
      p: pairResult.p,
      adjP: config.adjP != null ? config.adjP : pairResult.p,
      diff: Number.isFinite(pairResult.diff)
        ? pairResult.diff
        : (config.lognormalVariant ? NaN : (mean(rawAValues) - mean(rawBValues))),
      ciLow: pairResult.ciLow,
      ciHigh: pairResult.ciHigh,
      rangeMax,
      stat: statVal,
      statName,
      df: pairResult.df,
      labelA: config.labelA,
      labelB: config.labelB,
      effects: effectMetrics,
      effectParametric: formattedParamEffect,
      effectNonParametric: formattedNonParamEffect,
      method: config.method || 'standard',
      ratio: pairResult.ratio,
      scale: pairResult.scale,
      geoMeanA: pairResult.geoMeanA,
      geoMeanB: pairResult.geoMeanB
    };
  }

  function prepareSwarmPointLayoutConfig(params = {}){
    const rawValues = Array.isArray(params.valueList) ? params.valueList : [];
    const pointCount = rawValues.length;
    const pointCoords = new Float64Array(pointCount);
    const coordProjector = typeof params.coordProjector === 'function' ? params.coordProjector : value => value;
    for(let idx = 0; idx < pointCount; idx++){
      pointCoords[idx] = coordProjector(rawValues[idx]);
    }
    const traceIndex = params.traceIndex;
    const traceStyle = typeof params.getPointStyle === 'function' ? params.getPointStyle(traceIndex) : null;
    const overrideRadius = Number(params.pointRadiusOverride);
    const styleRadiusRaw = traceStyle && Number.isFinite(Number(traceStyle.size)) ? Number(traceStyle.size) : null;
    const allowAutoSize = !!params.autoSize && !(typeof params.hasExplicitPointSize === 'function' && params.hasExplicitPointSize(traceIndex));
    const styleRadius = allowAutoSize ? null : styleRadiusRaw;
    const resolvedRadius = Number.isFinite(overrideRadius) && overrideRadius > 0
      ? overrideRadius
      : (Number.isFinite(styleRadius) && styleRadius > 0 ? styleRadius : null);
    const fallbackRadius = params.pointRadius;
    const allowAdjustmentBase = params.allowRadiusAdjustment != null
      ? !!params.allowRadiusAdjustment
      : (params.autoSize ? allowAutoSize : true);
    const allowAdjustment = allowAdjustmentBase;
    const radiusCountExponent = allowAutoSize ? 0.85 : null;
    const explicitMaxHalfWidth = Number(params.maxHalfWidth);
    const spacingRadius = resolvedRadius != null ? resolvedRadius : fallbackRadius;
    const useStrictStripSpacing = params.widthScaleMode === 'density' && params.debugLabel === 'individual';
    const pitchHalfExtentLimit = useStrictStripSpacing
      ? computeStripHalfExtentLimit({
          minCenterPitch: params.minCenterPitch,
          gapFactor: params.interDatasetGapFactor,
          minGapPx: params.minInterDatasetGapPx
        })
      : null;
    const availableStrictHalfWidth = useStrictStripSpacing
      ? resolveStripAvailableHalfWidth({
          axisSpacing: params.localBand,
          pointRadius: spacingRadius,
          minCenterPitch: params.minCenterPitch,
          gapFactor: params.interDatasetGapFactor,
          minGapPx: params.minInterDatasetGapPx
        })
      : null;
    let resolvedMaxHalfWidth = Number.isFinite(explicitMaxHalfWidth) && explicitMaxHalfWidth > 0
      ? explicitMaxHalfWidth
      : availableStrictHalfWidth;
    if(useStrictStripSpacing && Number.isFinite(resolvedMaxHalfWidth) && resolvedMaxHalfWidth > 0){
      let stripSpreadFactor = computeSampleSpreadFactor(params.sampleCount, params.debugEnabled);
      const sampleCountValue = Math.max(0, Number(params.sampleCount) || 0);
      if(sampleCountValue > 0){
        const logCount = Math.log10(sampleCountValue + 1);
        const normalizedDelta = (logCount - STRIP_MEDIUM_SPREAD_LOG_CENTER) / STRIP_MEDIUM_SPREAD_LOG_SIGMA;
        const mediumCompression = Math.exp(-0.5 * normalizedDelta * normalizedDelta);
        const countScale = 1 - (1 - STRIP_MEDIUM_SPREAD_MIN_SCALE) * mediumCompression;
        stripSpreadFactor *= countScale;
      }
      stripSpreadFactor = Math.max(0.2, Math.min(1, stripSpreadFactor));
      const stripScaledHalfWidth = resolvedMaxHalfWidth * stripSpreadFactor;
      const stripMinHalfWidth = Math.max(spacingRadius * 1.05, 0.5);
      resolvedMaxHalfWidth = Math.max(stripMinHalfWidth, stripScaledHalfWidth);
    }
    const hardStripHalfWidthCap = useStrictStripSpacing && Number.isFinite(resolvedMaxHalfWidth) && resolvedMaxHalfWidth > 0
      ? resolvedMaxHalfWidth
      : null;
    const swarmPointRadius = resolvedRadius != null ? resolvedRadius : fallbackRadius;
    const approximateLayoutRadius = Number.isFinite(Number(fallbackRadius)) && Number(fallbackRadius) > 0
      ? Number(fallbackRadius)
      : swarmPointRadius;
    const effectiveShape = traceStyle && traceStyle.shape ? traceStyle.shape : 'circle';
    const canvasPointLayerEnabled = shouldUseBoxPointCanvasPreview(params.drawOpts, {
        pointCount,
        threshold: params.canvasThreshold
      })
      && BATCHABLE_POINT_SHAPES.has(effectiveShape)
      && canUseBoxPointResizeCanvas();
    const useApproximateCanvas = canvasPointLayerEnabled
      && shouldUseBoxDensityPointCanvas({
        pointCount,
        threshold: params.approximateThreshold,
        collectsPointByRow: params.collectPointsByRow instanceof Map
      });
    const approximateLayout = useApproximateCanvas
      ? buildBoxDensityPointLayout({
          coords: pointCoords,
          raws: rawValues,
          orientation: params.orientation,
          radius: approximateLayoutRadius,
          maxHalfWidth: resolvedMaxHalfWidth,
          widthScaleMode: params.widthScaleMode,
          violinBounds: params.violinBounds
        })
      : null;
    return {
      rawValues,
      pointCount,
      pointCoords,
      traceStyle,
      resolvedRadius,
      fallbackRadius,
      allowAdjustment,
      radiusCountExponent,
      useStrictStripSpacing,
      pitchHalfExtentLimit,
      resolvedMaxHalfWidth,
      hardStripHalfWidthCap,
      swarmPointRadius,
      approximateLayoutRadius,
      effectiveShape,
      canvasPointLayerEnabled,
      useApproximateCanvas,
      approximateLayout
    };
  }

  function getThemeAwareDefaultPalette(options = {}){
    const schemeId = typeof options.schemeId === 'string' && options.schemeId.trim()
      ? options.schemeId.trim().toLowerCase()
      : getBoxSelectedColorSchemeId();
    if(schemeId === 'dark'){
      return DEFAULT_BOX_COLORS;
    }
    return getBoxDefaultPalette(options.tableFormat);
  }

  function getGrayscaleUnifiedFillColor(){
    return DEFAULT_GRAYSCALE_UNIFIED_FILL;
  }

  function resolveThemeAwareDefaultTraceColors(options = {}){
    const schemeId = typeof options.schemeId === 'string' && options.schemeId.trim()
      ? options.schemeId.trim().toLowerCase()
      : getBoxSelectedColorSchemeId();
    const tableFormat = normalizeBoxTableFormat(options.tableFormat || state.tableFormat);
    const palette = getThemeAwareDefaultPalette({ schemeId, tableFormat });
    const colorIndexRaw = Number(options.colorIndex);
    const colorIndex = Number.isInteger(colorIndexRaw) && colorIndexRaw >= 0 ? colorIndexRaw : 0;
    const paletteColor = palette[colorIndex % Math.max(1, palette.length)] || getBoxDefaultFillColor(tableFormat);
    const rawFill = typeof options.fillColor === 'string' ? options.fillColor.trim() : '';
    const rawBorder = typeof options.borderColor === 'string' ? options.borderColor.trim() : '';
    const preferUnifiedDefault = options.preferUnifiedDefault === true;
    const darkPaletteFallback = DEFAULT_BOX_COLORS[colorIndex % Math.max(1, DEFAULT_BOX_COLORS.length)] || paletteColor;
    const grayscaleUnifiedFill = getGrayscaleUnifiedFillColor();

    if(schemeId === 'dark'){
      const fillNeedsThemeDefault = !rawFill || isColorTokenBlack(rawFill) || rawFill.toLowerCase() === '#ffffff' || rawFill.toLowerCase() === 'white';
      const borderNeedsThemeDefault = !rawBorder || isColorTokenBlack(rawBorder) || rawBorder.toLowerCase() === '#ffffff' || rawBorder.toLowerCase() === 'white';
      const fillColor = fillNeedsThemeDefault ? darkPaletteFallback : rawFill;
      const borderSeed = fillColor || darkPaletteFallback;
      const borderColor = borderNeedsThemeDefault ? shadeColor(borderSeed, -30) : rawBorder;
      return { fillColor: fillColor || darkPaletteFallback, borderColor: borderColor || shadeColor(borderSeed, -30) };
    }

    if(isBoxGrayscaleScheme(schemeId)){
      const fallbackFill = preferUnifiedDefault ? grayscaleUnifiedFill : paletteColor;
      const fillNeedsThemeDefault = !rawFill || isColorTokenBlack(rawFill) || isColorTokenWhite(rawFill);
      const borderNeedsThemeDefault = !rawBorder || isColorTokenBlack(rawBorder) || isColorTokenWhite(rawBorder);
      const fillColor = fillNeedsThemeDefault ? fallbackFill : rawFill;
      const borderSeed = fillColor || fallbackFill;
      const borderColor = borderNeedsThemeDefault ? shadeColor(borderSeed, -30) : rawBorder;
      return { fillColor: fillColor || fallbackFill, borderColor: borderColor || shadeColor(borderSeed, -30) };
    }

    const fillColor = rawFill || paletteColor;
    const borderSeed = fillColor || paletteColor;
    const borderColor = rawBorder || shadeColor(borderSeed, -30);
    return { fillColor: fillColor || paletteColor, borderColor: borderColor || shadeColor(borderSeed, -30) };
  }

  function getBoxSelectedColorSchemeId(){
    const colorSchemes = Shared.colorSchemes;
    if(colorSchemes && typeof colorSchemes.getSelectedSchemeId === 'function'){
      const selected = colorSchemes.getSelectedSchemeId('box');
      if(typeof selected === 'string' && selected.trim()){
        return selected.trim().toLowerCase();
      }
    }
    return getBoxDefaultColorSchemeId(state.tableFormat);
  }

  function syncBoxThemeSurfaceForCurrentScheme(overrideSchemeId){
    const schemeId = typeof overrideSchemeId === 'string' && overrideSchemeId.trim()
      ? overrideSchemeId.trim().toLowerCase()
      : getBoxSelectedColorSchemeId();
    const isDarkScheme = schemeId === 'dark';
    const surfaceColor = isDarkScheme ? '#000000' : '';
    if(els?.svgBox?.style){
      if(surfaceColor){
        els.svgBox.style.backgroundColor = surfaceColor;
      }else{
        els.svgBox.style.removeProperty('background-color');
      }
    }
    if(els?.plotDiv?.style){
      if(surfaceColor){
        els.plotDiv.style.backgroundColor = surfaceColor;
      }else{
        els.plotDiv.style.removeProperty('background-color');
      }
    }
  }

  function tryApplyBoxThemeBackgroundLive(schemeIdRaw){
    const schemeId = typeof schemeIdRaw === 'string' && schemeIdRaw.trim()
      ? schemeIdRaw.trim().toLowerCase()
      : getBoxSelectedColorSchemeId();
    const svg = els?.plotDiv?.querySelector?.('svg') || null;
    syncBoxThemeSurfaceForCurrentScheme(schemeId);
    if(!svg){
      return false;
    }
    const backgroundRect = svg.querySelector?.('[data-color-scheme-background="1"]') || null;
    if(schemeId === 'dark'){
      if(backgroundRect){
        backgroundRect.setAttribute('fill', '#000000');
        return true;
      }
      return false;
    }
    if(backgroundRect && backgroundRect.parentNode){
      backgroundRect.parentNode.removeChild(backgroundRect);
      return true;
    }
    return true;
  }

  function syncBoxDefaultColorSchemeForFormat(tableFormat, options = {}){
    const nextFormat = normalizeBoxTableFormat(tableFormat);
    const desiredScheme = getBoxDefaultColorSchemeId(nextFormat);
    const previousFormat = normalizeBoxTableFormat(options.previousFormat || nextFormat);
    const previousDefaultScheme = getBoxDefaultColorSchemeId(previousFormat);
    const currentScheme = getBoxSelectedColorSchemeId();
    const activeTab = global.Main?.session?.getActiveTab?.() || null;
    const explicitScheme = activeTab?.type === 'box' && typeof activeTab?.payload?.config?.colorScheme === 'string'
      ? activeTab.payload.config.colorScheme.trim().toLowerCase()
      : '';
    if(explicitScheme){
      if(explicitScheme !== previousDefaultScheme){
        return false;
      }
      if(explicitScheme === desiredScheme){
        return false;
      }
    }
    const colorSchemes = Shared.colorSchemes;
    if(!colorSchemes || typeof colorSchemes.applyToActiveTab !== 'function'){
      return false;
    }
    if(explicitScheme === desiredScheme || currentScheme === desiredScheme){
      return false;
    }
    return colorSchemes.applyToActiveTab('box', desiredScheme);
  }
