            const fillAlpha = Number.isFinite(Number(config.fillOpacity)) ? Number(config.fillOpacity) : 1;
            ctx.globalAlpha = Math.max(0, Math.min(1, fillAlpha));
            ctx.fillStyle = config.fill;
            ctx.fill();
