            const strokeAlpha = Number.isFinite(Number(config.strokeOpacity)) ? Number(config.strokeOpacity) : Number(config.fillOpacity);
            ctx.globalAlpha = Math.max(0, Math.min(1, Number.isFinite(strokeAlpha) ? strokeAlpha : 1));
